import {
  FormElementParams,
  StateObject,
  UpdateTypeDetail,
  type FormOptsType,
} from './CogsState';
import { pluginStore } from './pluginStore';
import {
  createMetadataContext,
  createScopedMetadataContext,
  toDeconstructedMethods,
} from './plugins';
import React, {
  memo,
  RefObject,
  useCallback,
  useEffect,
  useLayoutEffect,
  useRef,
  useState,
  useMemo,
} from 'react';
import { getGlobalStore, ValidationError, ValidationSeverity } from './store';
import { useInView } from 'react-intersection-observer';
import { v4 as uuidv4 } from 'uuid';
import { isDeepEqual } from './utility';
import { runValidation } from './validation';

const {
  getInitialOptions,

  getShadowMetadata,
  setShadowMetadata,
  getShadowValue,

  registerComponent,
  unregisterComponent,

  notifyPathSubscribers,
  subscribeToPath,
} = getGlobalStore.getState();
const { stateHandlers, notifyFormUpdate } = pluginStore.getState();

export type ValidationWrapperProps = {
  formOpts?: FormOptsType;
  path: string[];
  stateKey: string;
  children: React.ReactNode;
};

export function ValidationWrapper({
  formOpts,
  path,
  stateKey,
  children,
}: ValidationWrapperProps) {
  const { getInitialOptions, getShadowMetadata, getShadowValue } =
    getGlobalStore.getState();
  const thisStateOpts = getInitialOptions(stateKey!);

  const shadowMeta = getShadowMetadata(stateKey!, path);
  const validationState = shadowMeta?.validation;

  const status = validationState?.status || 'NOT_VALIDATED';

  const errors = (validationState?.errors || []).map((err) => ({
    ...err,
    path: path,
  })) as ValidationError[];
  const errorMessages = errors
    .filter((err) => err.severity === 'error')
    .map((err) => err.message);
  const warningMessages = errors
    .filter((err) => err.severity === 'warning')
    .map((err) => err.message);

  // Use first error, or first warning if no errors
  const message = errorMessages[0] || warningMessages[0];
  const primarySeverity: ValidationSeverity =
    errorMessages.length > 0
      ? 'error'
      : warningMessages.length > 0
        ? 'warning'
        : undefined;
  const { registeredPlugins } = pluginStore.getState();
  const pluginsApi: any = {};

  // We iterate over ALL registered plugins in the app.
  registeredPlugins.forEach((plugin) => {
    // A plugin is considered "active" for this state key if its name
    // exists as a key in the options (e.g., options.syncPlugin exists).
    if (thisStateOpts && thisStateOpts.hasOwnProperty(plugin.name)) {
      const pluginName = plugin.name;

      // Now we can safely build the API for this active plugin.
      const hookData = pluginStore
        .getState()
        .getHookResult(stateKey, pluginName);

      const scopedMetadata = createScopedMetadataContext(
        stateKey,
        pluginName,
        path
      );

      pluginsApi[pluginName] = {
        hookData,
        getFieldMetaData: scopedMetadata.getFieldMetaData,
        setFieldMetaData: scopedMetadata.setFieldMetaData,
      };
    }
  });
  return (
    <>
      {thisStateOpts?.formElements?.validation &&
      !formOpts?.validation?.disable ? (
        thisStateOpts.formElements!.validation!({
          children: (
            <React.Fragment key={path.toString()}>{children}</React.Fragment>
          ),
          status, // Now passes the new ValidationStatus type
          message: formOpts?.validation?.hideMessage
            ? ''
            : formOpts?.validation?.message || message || '',
          severity: primarySeverity,
          hasErrors: errorMessages.length > 0,
          hasWarnings: warningMessages.length > 0,
          allErrors: errors,
          path: path,
          getData: () => getShadowValue(stateKey!, path),
          plugins: pluginsApi,
        })
      ) : (
        <React.Fragment key={path.toString()}>{children}</React.Fragment>
      )}
    </>
  );
}
export const MemoizedCogsItemWrapper = memo(
  ListItemWrapper,
  (prevProps, nextProps) => {
    // Re-render if any of these change:
    return (
      prevProps.itemPath.join('.') === nextProps.itemPath.join('.') &&
      prevProps.stateKey === nextProps.stateKey &&
      prevProps.itemComponentId === nextProps.itemComponentId &&
      prevProps.localIndex === nextProps.localIndex
    );
  }
);
export function ListItemWrapper({
  stateKey,
  itemComponentId,
  itemPath,
  localIndex,
  arraySetter,
  rebuildStateShape,
  renderFn,
}: {
  stateKey: string;
  itemComponentId: string;
  itemPath: string[];
  localIndex: number;
  arraySetter: any;

  rebuildStateShape: (options: {
    currentState: any;
    path: string[];
    componentId: string;
    meta?: any;
  }) => any;
  renderFn: (
    setter: any,
    index: number,

    arraySetter: any
  ) => React.ReactNode;
}) {
  const [, forceUpdate] = useState({});
  const { ref: inViewRef, inView } = useInView();
  const elementRef = useRef<HTMLDivElement | null>(null);

  const fullKey = [stateKey, ...itemPath].join('.');
  useRegisterComponent(stateKey, itemComponentId, forceUpdate);

  const setRefs = useCallback(
    (element: HTMLDivElement | null) => {
      elementRef.current = element;
      inViewRef(element); // This is the ref from useInView
    },
    [inViewRef]
  );

  useEffect(() => {
    const unsubscribe = subscribeToPath(fullKey, (e) => {
      forceUpdate({});
    });
    return () => unsubscribe();
  }, [fullKey]);

  const itemValue = getShadowValue(stateKey, itemPath);

  if (itemValue === undefined) {
    return null;
  }

  const itemSetter = rebuildStateShape({
    currentState: itemValue,
    path: itemPath,
    componentId: itemComponentId,
  });
  const children = renderFn(itemSetter, localIndex, arraySetter);

  return <div ref={setRefs}>{children}</div>;
}

export function FormElementWrapper({
  stateKey,
  path,
  rebuildStateShape,
  renderFn,
  formOpts,
  setState,
}: {
  stateKey: string;
  path: string[];
  rebuildStateShape: (options: {
    path: string[];
    componentId: string;
    meta?: any;
  }) => any;
  renderFn: (params: FormElementParams<any>) => React.ReactNode;
  formOpts?: FormOptsType;
  setState: any;
}) {
  const componentId = useRef(uuidv4()).current;

  const [, forceUpdate] = useState({});
  const formElementRef = useRef<any>(null);
  const stateKeyPathKey = [stateKey, ...path].join('.');
  useRegisterComponent(stateKey, componentId, forceUpdate);
  // Get the shadow node to access typeInfo and schema
  const shadowNode = getGlobalStore.getState().getShadowNode(stateKey, path);
  const typeInfo = shadowNode?._meta?.typeInfo;

  const globalStateValue = getShadowValue(stateKey, path);
  const [localValue, setLocalValue] = useState<any>(globalStateValue);
  const isCurrentlyDebouncing = useRef(false);
  const debounceTimeoutRef = useRef<NodeJS.Timeout | null>(null);

  useEffect(() => {
    if (
      !isCurrentlyDebouncing.current &&
      !isDeepEqual(globalStateValue, localValue)
    ) {
      setLocalValue(globalStateValue);
    }
  }, [globalStateValue]);

  useEffect(() => {
    const { getShadowMetadata, setShadowMetadata } = getGlobalStore.getState();

    // Initialize clientActivityState if needed
    const currentMeta = getShadowMetadata(stateKey, path) || {};
    if (!currentMeta.clientActivityState) {
      currentMeta.clientActivityState = { elements: new Map() };
    }

    // Detect element type from the ref
    const detectElementType = () => {
      const el = formElementRef.current;
      if (!el) return 'input';
      const tagName = el.tagName.toLowerCase();
      if (tagName === 'textarea') return 'textarea';
      if (tagName === 'select') return 'select';
      if (tagName === 'input') {
        const type = (el as HTMLInputElement).type;
        if (type === 'checkbox') return 'checkbox';
        if (type === 'radio') return 'radio';
        if (type === 'range') return 'range';
        if (type === 'file') return 'file';
      }
      return 'input';
    };

    // Add this element to the Map
    currentMeta.clientActivityState.elements.set(componentId, {
      domRef: formElementRef,
      elementType: detectElementType(),
      inputType: formElementRef.current?.type,
      mountedAt: Date.now(),
    });

    setShadowMetadata(stateKey, path, currentMeta);

    // Subscribe to path updates
    const unsubscribe = getGlobalStore
      .getState()
      .subscribeToPath(stateKeyPathKey, (newValue) => {
        if (!isCurrentlyDebouncing.current && localValue !== newValue) {
          forceUpdate({});
        }
      });

    // Cleanup
    return () => {
      unsubscribe();

      if (debounceTimeoutRef.current) {
        clearTimeout(debounceTimeoutRef.current);
        isCurrentlyDebouncing.current = false;
      }

      // Remove element from Map
      const meta = getGlobalStore.getState().getShadowMetadata(stateKey, path);
      if (meta?.clientActivityState?.elements) {
        meta.clientActivityState.elements.delete(componentId);
        setShadowMetadata(stateKey, path, meta);
      }
    };
  }, []);

  const debouncedUpdate = useCallback(
    (newValue: any) => {
      // Type conversion logic (keep existing)
      if (typeInfo) {
        if (typeInfo.type === 'number' && typeof newValue === 'string') {
          newValue =
            newValue === ''
              ? typeInfo.nullable
                ? null
                : (typeInfo.default ?? 0)
              : Number(newValue);
        } else if (
          typeInfo.type === 'boolean' &&
          typeof newValue === 'string'
        ) {
          newValue = newValue === 'true' || newValue === '1';
        } else if (typeInfo.type === 'date' && typeof newValue === 'string') {
          newValue = new Date(newValue);
        }
      } else {
        const currentType = typeof globalStateValue;
        if (currentType === 'number' && typeof newValue === 'string') {
          newValue = newValue === '' ? 0 : Number(newValue);
        }
      }

      setLocalValue(newValue);

      // Update input activity details
      const { getShadowMetadata, setShadowMetadata } =
        getGlobalStore.getState();
      const meta = getShadowMetadata(stateKey, path);
      if (meta?.clientActivityState?.elements?.has(componentId)) {
        const element = meta.clientActivityState.elements.get(componentId);
        if (element && element.currentActivity?.type === 'focus') {
          element!.currentActivity.details = {
            ...element!.currentActivity.details,
            value: newValue,
            previousValue:
              element!.currentActivity.details?.value || globalStateValue,
            inputLength:
              typeof newValue === 'string' ? newValue.length : undefined,
            keystrokeCount:
              (element!.currentActivity.details?.keystrokeCount || 0) + 1,
          };
          setShadowMetadata(stateKey, path, meta);
        }
      }
      const element = meta?.clientActivityState?.elements?.get(componentId);

      // Notify plugins
      notifyFormUpdate({
        stateKey,
        activityType: 'input', // Changed from 'type'
        path,
        timestamp: Date.now(),
        details: {
          value: newValue,
          inputLength:
            typeof newValue === 'string' ? newValue.length : undefined,
          isComposing: false, // You'd need to track this from the actual input event
          isPasting: false, // You'd need to track this from paste events
          keystrokeCount:
            (element?.currentActivity?.details?.keystrokeCount || 0) + 1,
        },
      });
      // Validation (keep existing)
      const virtualOperation: UpdateTypeDetail = {
        stateKey,
        path,
        newValue: newValue,
        updateType: 'update',
        timeStamp: Date.now(),
        status: 'new',
        oldValue: globalStateValue,
      };
      runValidation(virtualOperation, 'onChange');

      // Debounce state update (keep existing)
      isCurrentlyDebouncing.current = true;
      if (debounceTimeoutRef.current) {
        clearTimeout(debounceTimeoutRef.current);
      }

      const debounceTime = formOpts?.debounceTime ?? 200;
      debounceTimeoutRef.current = setTimeout(() => {
        isCurrentlyDebouncing.current = false;
        setState(newValue, path, {
          updateType: 'update',
          validationTrigger: 'onChange',
        });
      }, debounceTime);
    },
    [
      setState,
      path,
      formOpts?.debounceTime,
      typeInfo,
      globalStateValue,
      stateKey,
      componentId,
    ]
  );

  const handleFocus = useCallback(() => {
    const { getShadowMetadata, setShadowMetadata } = getGlobalStore.getState();

    // Update element's current activity
    const meta = getShadowMetadata(stateKey, path);
    if (meta?.clientActivityState?.elements?.has(componentId)) {
      const element = meta.clientActivityState.elements.get(componentId)!;
      element.currentActivity = {
        type: 'focus',
        startTime: Date.now(),
        details: {
          value: localValue,
          inputLength:
            typeof localValue === 'string' ? localValue.length : undefined,
        },
      };
      setShadowMetadata(stateKey, path, meta);
    }

    // Notify plugins
    notifyFormUpdate({
      stateKey,
      activityType: 'focus', // Changed from 'type'
      path,
      timestamp: Date.now(),
      details: {
        cursorPosition: formElementRef.current?.selectionStart,
      },
    });
  }, [stateKey, path, componentId, localValue]);
  const handleBlur = useCallback(() => {
    const { getShadowMetadata, setShadowMetadata } = getGlobalStore.getState();

    // Clear debounce if active
    if (debounceTimeoutRef.current) {
      clearTimeout(debounceTimeoutRef.current);
      debounceTimeoutRef.current = null;
      isCurrentlyDebouncing.current = false;
      setState(localValue, path, {
        updateType: 'update',
        validationTrigger: 'onBlur',
      });
    }

    // Clear element's current activity
    const meta = getShadowMetadata(stateKey, path);
    if (meta?.clientActivityState?.elements?.has(componentId)) {
      const element = meta.clientActivityState.elements.get(componentId)!;
      element.currentActivity = undefined;
      setShadowMetadata(stateKey, path, meta);
    }
    const focusStartTime =
      meta?.clientActivityState?.elements?.get(componentId)?.currentActivity
        ?.startTime;

    // Notify plugins
    notifyFormUpdate({
      stateKey,
      activityType: 'blur', // Changed from 'type'
      path,
      timestamp: Date.now(),
      duration: focusStartTime ? Date.now() - focusStartTime : undefined,
      details: {
        duration: focusStartTime ? Date.now() - focusStartTime : 0,
      },
    });

    // Run validation if configured
    const validationOptions = getInitialOptions(stateKey)?.validation;
    if (validationOptions?.onBlur) {
      const virtualOperation: UpdateTypeDetail = {
        stateKey,
        path,
        newValue: localValue,
        updateType: 'update',
        timeStamp: Date.now(),
        status: 'new',
        oldValue: globalStateValue,
      };
      runValidation(virtualOperation, 'onBlur');
    }
  }, [localValue, setState, path, stateKey, componentId, globalStateValue]);

  const baseState = rebuildStateShape({
    path: path,
    componentId: componentId,
    meta: undefined,
  });

  const stateWithInputProps = new Proxy(baseState, {
    get(target, prop) {
      if (prop === '$inputProps') {
        return {
          value: localValue ?? '',
          onChange: (e: any) => {
            debouncedUpdate(e.target.value);
          },
          onFocus: handleFocus,
          onBlur: handleBlur,
          ref: formElementRef,
        };
      }

      return target[prop];
    },
  });

  const initialElement = renderFn(stateWithInputProps);

  return (
    <ValidationWrapper formOpts={formOpts} path={path} stateKey={stateKey}>
      {initialElement}
    </ValidationWrapper>
  );
}
export function useRegisterComponent(
  stateKey: string,
  componentId: string,
  forceUpdate: (o: object) => void
) {
  const fullComponentId = `${stateKey}////${componentId}`;

  useLayoutEffect(() => {
    registerComponent(stateKey, fullComponentId, {
      forceUpdate: () => forceUpdate({}),
      paths: new Set(),
      reactiveType: ['component'],
    });
    return () => {
      unregisterComponent(stateKey, fullComponentId);
    };
  }, [stateKey, fullComponentId]);
}

export function IsolatedComponentWrapper({
  stateKey,
  path, // The path of the parent node (e.g. ['form'])
  dependencies, // NEW: Optional array of Proxy objects or path arrays
  rebuildStateShape,
  renderFn,
}: {
  stateKey: string;
  path: string[];
  dependencies?: any[]; // The explicit list of dependencies
  rebuildStateShape: (options: any) => any;
  renderFn: (state: any) => React.ReactNode;
}) {
  const [componentId] = useState(() => uuidv4());
  const [, forceUpdate] = useState({});

  useRegisterComponent(stateKey, componentId, forceUpdate);

  const pathsToSubscribe = useMemo(() => {
    if (dependencies && dependencies.length > 0) {
      return dependencies.map((dep) => {
        return [stateKey, ...dep.$_path].join('.');
      });
    }

    return [[stateKey, ...path].join('.')];
  }, [stateKey, path, dependencies]);

  // 2. Subscribe to ALL calculated paths
  useEffect(() => {
    const store = getGlobalStore.getState();

    // Create an array of unsubscribe functions
    const unsubs = pathsToSubscribe.map((fullPathKey) => {
      return store.subscribeToPath(fullPathKey, () => {
        forceUpdate({});
      });
    });

    return () => {
      unsubs.forEach((unsub) => unsub());
    };
  }, [pathsToSubscribe]);

  const baseState = rebuildStateShape({
    path: path,
    componentId: componentId,
    meta: undefined,
  });

  return <>{renderFn(baseState)}</>;
}
// 1. Define the MINIMAL props needed.
type PluginWrapperProps = {
  children: React.ReactNode;
  stateKey: string;
  path: string[];
  pluginName: string;
  wrapperDepth: number;
};

const PluginWrapper = memo(function PluginWrapper({
  children,
  stateKey,
  path,
  pluginName,
  wrapperDepth,
}: PluginWrapperProps) {
  const [, forceUpdate] = useState({});

  useEffect(() => {
    const fullPathKey = [stateKey, ...path].join('.');
    const unsubscribe = getGlobalStore
      .getState()
      .subscribeToPath(fullPathKey, () => {
        forceUpdate({});
      });
    return unsubscribe;
  }, [stateKey, path]);

  const plugin = pluginStore
    .getState()
    .registeredPlugins.find((p) => p.name === pluginName);

  const stateHandler: StateObject<any> | undefined = pluginStore
    .getState()
    .stateHandlers.get(stateKey);

  const typeInfo = getGlobalStore.getState().getShadowNode(stateKey, path)
    ?._meta?.typeInfo;

  const options = pluginStore
    .getState()
    .pluginOptions.get(stateKey)
    ?.get(pluginName);

  const hookData = pluginStore.getState().getHookResult(stateKey, pluginName);

  if (!plugin?.formWrapper || !stateHandler) {
    return <>{children}</>;
  }

  const deconstructed = toDeconstructedMethods(stateHandler);
  const scopedMetadataContext = createScopedMetadataContext(
    stateKey,
    plugin.name,
    path
  );
  return plugin.formWrapper({
    element: children,
    path,
    stateKey,
    pluginName: plugin.name,
    ...deconstructed,

    ...scopedMetadataContext,
    options,
    hookData,
    fieldType: typeInfo?.type,
    wrapperDepth,
  });
});
